def cache_decorator(timeout=60):
    def decorator(fn):
        @functools.wraps(fn)
        def wrapper(*args, **kwargs):
            cache_key = f"cache_{fn.__name__}_{args}_{kwargs}"
            cached_result = redis_client.get(cache_key)
